import React, { useState, useEffect, useContext } from 'react';
import { db } from '../firebase/config';
import {
  collection, addDoc, updateDoc, deleteDoc, doc,
  onSnapshot, orderBy, query, serverTimestamp
} from 'firebase/firestore';
import { Trash2, Upload, Plus, Pencil, Package } from 'lucide-react';
import { ToastContext } from '../App';
import './ProductManager.css';

const CATEGORIES = ['rings','necklaces','earrings','bracelets','watches','anklets','charms','pendants'];
const SECTIONS   = [
  { value: 'bestSellers', label: 'Best Sellers' },
  { value: 'newArrivals', label: 'New Arrivals' },
];

const EMPTY = { name: '', price: '', category: 'rings', section: 'bestSellers', image: '' };

export default function ProductManager() {
  const { showToast } = useContext(ToastContext);
  const [form, setForm]         = useState(EMPTY);
  const [products, setProducts] = useState([]);
  const [filter, setFilter]     = useState('all');
  const [editId, setEditId]     = useState(null);
  const [loading, setLoading]   = useState(false);

  // ── Real-time products ──
  useEffect(() => {
    const q = query(collection(db, 'products'), orderBy('createdAt', 'desc'));
    const unsub = onSnapshot(q, snap => {
      setProducts(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    }, () => {});
    return () => unsub();
  }, []);

  // ── Cloudinary Upload ──
  const openCloudinary = () => {
    if (!window.cloudinary) {
      showToast('Cloudinary widget not loaded — check index.html', 'error');
      return;
    }
    window.cloudinary.openUploadWidget(
      {
        cloudName:    'dy2mutnk6',   // ← Replace
        uploadPreset: 'aurelia_upload',       // ← Replace
        sources: ['local', 'url', 'camera'],
        multiple: false,
        maxFileSize: 5000000,
        folder: 'aurelia-products',
        cropping: true,
        croppingAspectRatio: 1,
      },
      (error, result) => {
        if (!error && result?.event === 'success') {
          setForm(f => ({ ...f, image: result.info.secure_url }));
          showToast('Image uploaded to Cloudinary ✓');
        }
      }
    );
  };

  // ── Add or Update ──
  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.name || !form.price || !form.image) {
      showToast('Please fill all fields and add an image', 'error');
      return;
    }

    setLoading(true);
    try {
      const productData = {
        name:     form.name,
        price:    Number(form.price),
        category: form.category,
        section:  form.section,
        image:    form.image,
      };

      if (editId) {
        await updateDoc(doc(db, 'products', editId), productData);
        showToast('Product updated successfully ✓');
        setEditId(null);
      } else {
        await addDoc(collection(db, 'products'), {
          ...productData,
          createdAt: serverTimestamp(),
        });
        showToast('Product added — live on client site! 🚀');
      }
      setForm(EMPTY);
    } catch (err) {
      showToast('Error saving product', 'error');
    }
    setLoading(false);
  };

  // ── Edit ──
  const handleEdit = (product) => {
    setForm({
      name:     product.name,
      price:    String(product.price),
      category: product.category || 'rings',
      section:  product.section  || 'bestSellers',
      image:    product.image    || '',
    });
    setEditId(product.id);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // ── Delete ──
  const handleDelete = async (id) => {
    if (!window.confirm('Delete this product?')) return;
    await deleteDoc(doc(db, 'products', id));
    showToast('Product deleted');
    if (editId === id) { setEditId(null); setForm(EMPTY); }
  };

  // ── Cancel edit ──
  const cancelEdit = () => { setEditId(null); setForm(EMPTY); };

  // ── Filter ──
  const filtered = filter === 'all'
    ? products
    : products.filter(p => p.section === filter);

  return (
    <div className="product-manager">

      {/* HEADER */}
      <div className="page-header">
        <div>
          <h1 className="page-title">Products</h1>
          <p className="page-sub">Add, manage and organize your jewellery collection.</p>
        </div>
        <span className="product-count">{products.length} products</span>
      </div>

      {/* ── ADD / EDIT FORM ── */}
      <div className="card product-form">
        <h3 className="form-title">
          {editId ? <><Pencil size={17} /> Edit Product</> : <><Plus size={17} /> Add New Product</>}
        </h3>

        <form onSubmit={handleSubmit}>
          <div className="form-grid">
            <div className="form-field">
              <label className="field-label">Product Name</label>
              <input className="field-input" placeholder="e.g. Diamond Solitaire Ring"
                value={form.name} onChange={e => setForm({...form, name: e.target.value})} />
            </div>
            <div className="form-field">
              <label className="field-label">Price ($)</label>
              <input className="field-input" type="number" placeholder="e.g. 1299"
                value={form.price} onChange={e => setForm({...form, price: e.target.value})} />
            </div>
            <div className="form-field">
              <label className="field-label">Category</label>
              <select className="field-input" value={form.category}
                onChange={e => setForm({...form, category: e.target.value})}>
                {CATEGORIES.map(c => (
                  <option key={c} value={c}>{c.charAt(0).toUpperCase()+c.slice(1)}</option>
                ))}
              </select>
            </div>
            <div className="form-field">
              <label className="field-label">Section</label>
              <select className="field-input" value={form.section}
                onChange={e => setForm({...form, section: e.target.value})}>
                {SECTIONS.map(s => (
                  <option key={s.value} value={s.value}>{s.label}</option>
                ))}
              </select>
            </div>
          </div>

          {/* IMAGE */}
          <div className="image-section">
            <label className="field-label">Product Image</label>
            <div className="image-options">
              <button type="button" className="upload-cloudinary-btn" onClick={openCloudinary}>
                <Upload size={15} /> Upload Image
              </button>
              <span className="or-divider">OR</span>
              <input className="field-input url-input" placeholder="Paste image URL here..."
                value={form.image} onChange={e => setForm({...form, image: e.target.value})} />
            </div>

            {form.image && (
              <div className="image-preview">
                <img src={form.image} alt="Preview"
                  onError={e => { e.target.src = ''; e.target.alt = 'Invalid URL'; }} />
                <button type="button" className="remove-preview"
                  onClick={() => setForm({...form, image: ''})}>✕</button>
                <span className="preview-label">Preview</span>
              </div>
            )}
          </div>

          <div className="form-actions">
            <button className="btn-primary" type="submit" disabled={loading}>
              {loading ? 'Saving...' : editId ? 'Update Product' : 'Add Product'}
            </button>
            {editId && (
              <button className="btn-secondary" type="button" onClick={cancelEdit}>
                Cancel Edit
              </button>
            )}
            {!editId && (
              <button className="btn-secondary" type="button"
                onClick={() => setForm(EMPTY)}>Clear</button>
            )}
          </div>
        </form>
      </div>

      {/* ── PRODUCT QUEUE / LIST ── */}
      <div className="products-list-section">
        <div className="list-header">
          <h3 className="section-heading">All Products</h3>
          <div className="filter-tabs">
            {[
              { key:'all', label:'All' },
              { key:'bestSellers', label:'Best Sellers' },
              { key:'newArrivals', label:'New Arrivals' },
            ].map(f => (
              <button key={f.key}
                className={`filter-tab ${filter === f.key ? 'active' : ''}`}
                onClick={() => setFilter(f.key)}>
                {f.label}
              </button>
            ))}
          </div>
        </div>

        {filtered.length === 0 ? (
          <div className="empty-state card">
            <Package size={44} strokeWidth={1} color="#ccc" />
            <p>No products yet</p>
            <span>Products you add will appear here as a live queue</span>
          </div>
        ) : (
          <div className="product-queue">
            {filtered.map(p => (
              <div className={`product-queue-item card ${editId === p.id ? 'editing' : ''}`} key={p.id}>
                <div className="pq-image">
                  {p.image
                    ? <img src={p.image} alt={p.name} />
                    : <span className="pq-placeholder">?</span>
                  }
                </div>
                <div className="pq-info">
                  <p className="pq-name">{p.name}</p>
                  <div className="pq-meta">
                    <span className="pq-category">{p.category || '—'}</span>
                    <span className={`pq-section ${p.section || ''}`}>
                      {p.section === 'bestSellers' ? 'Best Seller' : p.section === 'newArrivals' ? 'New Arrival' : '—'}
                    </span>
                  </div>
                </div>
                <p className="pq-price">${(p.price || 0).toLocaleString()}</p>
                <div className="pq-actions">
                  <button className="pq-edit" title="Edit" onClick={() => handleEdit(p)}>
                    <Pencil size={15} />
                  </button>
                  <button className="pq-delete" title="Delete" onClick={() => handleDelete(p.id)}>
                    <Trash2 size={15} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
